   128→// TestHookRunner_SimulateStop_SubagentOnlyChanges tests that the stop hook correctly
   129→// creates a checkpoint when ONLY subagents (spawned via Task tool) modify files.
   130→// This is a regression test for ENT-297 where subagent file modifications were invisible
   131→// to checkpoint detection because ExtractModifiedFiles only looked at the main transcript.
   132→// The fix (ExtractAllModifiedFiles) also reads subagent transcript files.
   133→func TestHookRunner_SimulateStop_SubagentOnlyChanges(t *testing.T) {
   134→	t.Parallel()
   135→	RunForAllStrategiesWithRepoEnv(t, func(t *testing.T, env *TestEnv, strategyName string) {
   136→		// Create a session
   137→		session := env.NewSession()
   138→
   139→		// Simulate user prompt submit first (captures pre-prompt state)
   140→		err := env.SimulateUserPromptSubmit(session.ID)
   141→		if err != nil {
   142→			t.Fatalf("SimulateUserPromptSubmit failed: %v", err)
   143→		}
   144→
   145→		// Record initial state for comparison
   146→		commitsBefore := env.GetGitLog()
   147→
   148→		// Create a file on disk (simulating what a subagent would write)
   149→		env.WriteFile("subagent_output.go", "package main\n\nfunc SubagentWork() {}\n")
   150→
   151→		// Build the main transcript manually. The main transcript contains ONLY
   152→		// a Task tool call (no Write/Edit). All file modifications happened in
   153→		// the subagent.
   154→		mainTranscript := NewTranscriptBuilder()
   155→		mainTranscript.AddUserMessage("Create a function in a new file")
   156→		mainTranscript.AddAssistantMessage("I'll delegate this to a subagent.")
   157→
   158→		// Add Task tool use
   159→		taskToolUseID := mainTranscript.AddTaskToolUse("", "Create the function")
   160→
   161→		// Add Task tool result with agentId
   162→		agentID := "sub123abc"
   163→		mainTranscript.AddTaskToolResult(taskToolUseID, agentID)
   164→
   165→		mainTranscript.AddAssistantMessage("The subagent completed the task.")
   166→
   167→		// Write the main transcript
   168→		if err := mainTranscript.WriteToFile(session.TranscriptPath); err != nil {
   169→			t.Fatalf("failed to write main transcript: %v", err)
   170→		}
   171→
   172→		// Create the subagent transcript file in the directory structure the Stop hook expects:
   173→		// <transcriptDir>/<modelSessionID>/subagents/agent-<agentID>.jsonl
   174→		transcriptDir := filepath.Dir(session.TranscriptPath)
   175→		subagentsDir := filepath.Join(transcriptDir, session.ID, "subagents")
   176→		subagentTranscriptPath := filepath.Join(subagentsDir, "agent-"+agentID+".jsonl")
   177→
   178→		// Build the subagent transcript with Write tool calls
   179→		subagentTranscript := NewTranscriptBuilder()
   180→		subagentTranscript.AddUserMessage("Create a function in a new file")
   181→		absFilePath := filepath.Join(env.RepoDir, "subagent_output.go")
   182→		toolID := subagentTranscript.AddToolUse("Write", absFilePath, "package main\n\nfunc SubagentWork() {}\n")
   183→		subagentTranscript.AddToolResult(toolID)
   184→		subagentTranscript.AddAssistantMessage("Done, I created the function.")
   185→
   186→		if err := subagentTranscript.WriteToFile(subagentTranscriptPath); err != nil {
   187→			t.Fatalf("failed to write subagent transcript: %v", err)
   188→		}
   189→
   190→		// Simulate stop - this should NOT error and should create a checkpoint
   191→		err = env.SimulateStop(session.ID, session.TranscriptPath)
   192→		if err != nil {
   193→			t.Fatalf("SimulateStop failed: %v", err)
   194→		}
   195→
   196→		// Verify checkpoint was created based on strategy type
   197→		switch strategyName {
   198→		case strategy.StrategyNameAutoCommit:
   199→			// Auto-commit creates a new commit on the active branch
   200→			commitsAfter := env.GetGitLog()
   201→			if len(commitsAfter) <= len(commitsBefore) {
   202→				t.Errorf("auto-commit: expected new commit to be created; commits before=%d, after=%d",
   203→					len(commitsBefore), len(commitsAfter))
   204→			}
   205→
   206→		case strategy.StrategyNameManualCommit:
   207→			// Manual-commit stores checkpoint data on the shadow branch
   208→			shadowBranch := env.GetShadowBranchName()
   209→			if !env.BranchExists(shadowBranch) {
   210→				t.Errorf("manual-commit: shadow branch %s should exist after checkpoint", shadowBranch)
   211→			}
   212→
   213→			// Verify session state was updated with checkpoint count
   214→			state, stateErr := env.GetSessionState(session.ID)
   215→			if stateErr != nil {
   216→				t.Fatalf("failed to get session state: %v", stateErr)
   217→			}
   218→			if state == nil {
   219→				t.Fatal("manual-commit: session state should exist after checkpoint")
   220→			}
   221→			if state.StepCount == 0 {
   222→				t.Error("manual-commit: session state should have non-zero step count")
   223→			}
   224→		}
   225→	})
   226→}
