   228→// TestUserPromptSubmit_ReinstallsOverwrittenHooks verifies that EnsureSetup is called
   229→// during user-prompt-submit (start of turn) and reinstalls hooks that were overwritten
   230→// by third-party tools like lefthook. This ensures hooks are in place before any
   231→// mid-turn commits the agent might make.
   232→func TestUserPromptSubmit_ReinstallsOverwrittenHooks(t *testing.T) {
   233→	t.Parallel()
   234→	RunForAllStrategiesWithRepoEnv(t, func(t *testing.T, env *TestEnv, strategyName string) {
   235→		hooksDir := filepath.Join(env.RepoDir, ".git", "hooks")
   236→		hookNames := strategy.ManagedGitHookNames()
   237→
   238→		// Step 1: First user-prompt-submit installs hooks via EnsureSetup
   239→		session := env.NewSession()
   240→		err := env.SimulateUserPromptSubmit(session.ID)
   241→		if err != nil {
   242→			t.Fatalf("First SimulateUserPromptSubmit failed: %v", err)
   243→		}
   244→
   245→		// Verify hooks are now installed
   246→		if !strategy.IsGitHookInstalledInDir(env.RepoDir) {
   247→			t.Fatal("hooks should be installed after first SimulateUserPromptSubmit")
   248→		}
   249→
   250→		// Step 2: Overwrite hooks with third-party content (simulating lefthook, husky, etc.)
   251→		for _, hookName := range hookNames {
   252→			hookPath := filepath.Join(hooksDir, hookName)
   253→			thirdPartyContent := "#!/bin/sh\n# Third-party hook manager\necho 'Running third-party hook'\n"
   254→			if err := os.WriteFile(hookPath, []byte(thirdPartyContent), 0o755); err != nil {
   255→				t.Fatalf("failed to overwrite hook %s: %v", hookName, err)
   256→			}
   257→		}
   258→
   259→		// Step 3: Verify hooks are no longer Entire hooks
   260→		if strategy.IsGitHookInstalledInDir(env.RepoDir) {
   261→			t.Fatal("hooks should NOT be detected as Entire hooks after overwrite")
   262→		}
   263→
   264→		// Step 4: Second user-prompt-submit should reinstall hooks
   265→		err = env.SimulateUserPromptSubmit(session.ID)
   266→		if err != nil {
   267→			t.Fatalf("Second SimulateUserPromptSubmit failed: %v", err)
   268→		}
   269→
   270→		// Step 5: Verify hooks are reinstalled
   271→		if !strategy.IsGitHookInstalledInDir(env.RepoDir) {
   272→			t.Error("hooks should be reinstalled after second SimulateUserPromptSubmit")
   273→		}
   274→
   275→		// Step 6: Verify the hooks chain to original hooks (backup should exist)
   276→		for _, hookName := range hookNames {
   277→			backupPath := filepath.Join(hooksDir, hookName+".pre-entire")
   278→			if _, err := os.Stat(backupPath); os.IsNotExist(err) {
   279→				t.Errorf("backup hook %s.pre-entire should exist", hookName)
   280→			}
   281→		}
   282→	})
   283→}
